  1	import { Popover, Stack } from '@patternfly/react-core';
  2	import React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { TempoResource, useTempoResources } from '../hooks/useTempoResources';
  5	import { TempoInstance } from '../hooks/useTempoInstance';
  6	import { HelpIcon } from '@patternfly/react-icons';
  7	import { TypeaheadSelect } from './TypeaheadSelect';
  8	
  9	interface TempoInstanceDropdownProps {
 10	  tempo: TempoInstance | undefined;
 11	  setTempo: (tempo: TempoInstance) => void;
 12	}
 13	
 14	interface TempoResourceOption {
 15	  value: string;
 16	  children: string;
 17	  tempo: TempoResource;
 18	}
 19	
 20	export const TempoInstanceDropdown = ({ tempo, setTempo }: TempoInstanceDropdownProps) => {
 21	  const { t } = useTranslation('plugin__distributed-tracing-console-plugin');
 22	  const { loading: tempoResourcesLoading, tempoResources } = useTempoResources();
 23	
 24	  const options: TempoResourceOption[] = (tempoResources ?? [])
 25	    .map((tempo) => ({
 26	      value: `${tempo.namespace}__${tempo.name}`,
 27	      children: `${tempo.namespace} / ${tempo.name}`,
 28	      tempo,
 29	    }))
 30	    .sort((a, b) => a.children.toString().localeCompare(b.children.toString()));
 31	
 32	  let selected: TempoResourceOption | undefined = undefined;
 33	  if (tempo) {
 34	    if (tempoResourcesLoading) {
 35	      // Preselect the dropdown option without waiting until the list of TempoResources is loaded to prevent flickering.
 36	      // To accomplish this, we'll create a slightly inaccurate TempoResourceSelectOption,
 37	      // because the kind and the list of tenants is not known before the list of TempoResources is loaded.
 38	      selected = {
 39	        value: `${tempo.namespace}__${tempo.name}`,
 40	        children: `${tempo.namespace} / ${tempo.name}`,
 41	        tempo: {
 42	          kind: 'TempoStack',
 43	          namespace: tempo.namespace,
 44	          name: tempo.name,
 45	          tenants: tempo.tenant ? [tempo.tenant] : undefined,
 46	        },
 47	      };
 48	      options.push(selected);
 49	    } else {
 50	      selected = options.find(
 51	        (o) => o.tempo.namespace == tempo.namespace && o.tempo.name == tempo.name,
 52	      );
 53	    }
 54	  }
 55	
 56	  const onSelect = (value?: string) => {
 57	    if (!value) return;
 58	
 59	    const option = options.find((o) => o.value === value);
 60	    if (option && option.value !== selected?.value) {
 61	      setTempo({
 62	        namespace: option.tempo.namespace,
 63	        name: option.tempo.name,
 64	        tenant: option.tempo.tenants?.[0], // select first tenant by default, or undefined if no tenants
 65	      });
 66	    }
 67	  };
 68	
 69	  return (
 70	    <>
 71	      <Stack>
 72	        <label htmlFor="tempoinstance-dropdown">
 73	          {t('Tempo Instance')}{' '}
 74	          <Popover
 75	            headerContent={<div>{t('Select a Tempo instance')}</div>}
 76	            bodyContent={<div>{t('tempoinstance_helptext')}</div>}
 77	          >
 78	            <HelpIcon />
 79	          </Popover>
 80	        </label>
 81	        <TypeaheadSelect
 82	          id="tempoinstance-dropdown"
 83	          width={320}
 84	          loading={tempoResourcesLoading}
 85	          placeholder={t('Select a Tempo instance')}
 86	          options={options}
 87	          selected={selected?.value}
 88	          setSelected={onSelect}
 89	        />
 90	      </Stack>
 91	      {selected?.tempo.tenants && selected.tempo.tenants.length > 0 && tempo && (
 92	        <Stack>
 93	          <label htmlFor="tenant-dropdown">{t('Tenant')}</label>
 94	          <TypeaheadSelect
 95	            id="tenant-dropdown"
 96	            width={200}
 97	            placeholder={t('Select a tenant')}
 98	            options={selected.tempo.tenants.map((t) => ({ value: t, children: t }))}
 99	            selected={tempo.tenant}
100	            setSelected={(tenant) => setTempo({ ...tempo, tenant })}
101	          />
102	        </Stack>
103	      )}
104	    </>
105	  );
106	};

